import{_ as a,c as n,o as s,d as e}from"./app.318e13ba.js";const g='{"title":"Setup Laravel API","description":"","frontmatter":{},"headers":[{"level":2,"title":"Install Sanctum","slug":"install-sanctum"},{"level":2,"title":"Install Fortify","slug":"install-fortify"},{"level":2,"title":"Database Seeding","slug":"database-seeding"}],"relativePath":"guide/setup-laravel-api.md"}',t={},p=e(`<h1 id="setup-laravel-api" tabindex="-1">Setup Laravel API <a class="header-anchor" href="#setup-laravel-api" aria-hidden="true">#</a></h1><p>Make sure you change the following in your .env file:</p><div class="language-php"><pre><code><span class="token constant">DB_HOST</span><span class="token operator">=</span><span class="token number">127.0</span><span class="token number">.0</span><span class="token number">.1</span>
</code></pre></div><p>To this:</p><div class="language-php"><pre><code><span class="token constant">DB_HOST</span><span class="token operator">=</span>mysql
</code></pre></div><p>or to this:</p><div class="language-php"><pre><code><span class="token constant">DB_HOST</span><span class="token operator">=</span>pgsql
</code></pre></div><p>Add a sender address in the .env so that email can be sent.</p><div class="language-php"><pre><code><span class="token constant">MAIL_FROM_ADDRESS</span><span class="token operator">=</span>test@test<span class="token operator">.</span>com
</code></pre></div><h2 id="install-sanctum" tabindex="-1">Install Sanctum <a class="header-anchor" href="#install-sanctum" aria-hidden="true">#</a></h2><p>The full documentation can be found on the <a href="https://laravel.com/docs/9.x/sanctum" target="_blank" rel="noopener noreferrer">Laravel website</a>.</p><div class="language-php"><pre><code>composer <span class="token keyword">require</span> laravel<span class="token operator">/</span>sanctum
php artisan vendor<span class="token punctuation">:</span>publish <span class="token operator">--</span>provider<span class="token operator">=</span><span class="token string double-quoted-string">&quot;Laravel\\Sanctum\\SanctumServiceProvider&quot;</span>
php artisan migrate
</code></pre></div><p>Sanctum needs some specific set up to enable it to work with a separate SPA. First lets add the following in your .env file:</p><div class="language-php"><pre><code><span class="token constant">SANCTUM_STATEFUL_DOMAINS</span><span class="token operator">=</span>localhost<span class="token punctuation">:</span><span class="token number">3000</span>
<span class="token constant">SPA_URL</span><span class="token operator">=</span>http<span class="token punctuation">:</span><span class="token comment">//localhost:3000</span>
<span class="token constant">SESSION_DOMAIN</span><span class="token operator">=</span>localhost
</code></pre></div><p>The stateful domain tells Sanctum which domain you are using for the SPA. You can find the full notes and config for this in the config/sanctum.php file. As we are using cookies and sessions for authentication you need to add a session domain. This determines which domain the cookie is available to in your application. Full notes can be found in the config/session.php file and the <a href="https://laravel.com/docs/9.x/sanctum#spa-authentication" target="_blank" rel="noopener noreferrer">official documentation</a>.</p><p>Add Sanctum&#39;s middleware to your api middleware group within your application&#39;s app/Http/Kernel.php file:</p><div class="language-php"><pre><code><span class="token string single-quoted-string">&#39;api&#39;</span> <span class="token operator">=&gt;</span> <span class="token punctuation">[</span>
    <span class="token class-name class-name-fully-qualified static-context"><span class="token punctuation">\\</span>Laravel<span class="token punctuation">\\</span>Sanctum<span class="token punctuation">\\</span>Http<span class="token punctuation">\\</span>Middleware<span class="token punctuation">\\</span>EnsureFrontendRequestsAreStateful</span><span class="token operator">::</span><span class="token keyword">class</span><span class="token punctuation">,</span>
    <span class="token string single-quoted-string">&#39;throttle:api&#39;</span><span class="token punctuation">,</span>
    <span class="token class-name class-name-fully-qualified static-context"><span class="token punctuation">\\</span>Illuminate<span class="token punctuation">\\</span>Routing<span class="token punctuation">\\</span>Middleware<span class="token punctuation">\\</span>SubstituteBindings</span><span class="token operator">::</span><span class="token keyword">class</span><span class="token punctuation">,</span>
<span class="token punctuation">]</span><span class="token punctuation">,</span>
</code></pre></div><h2 id="install-fortify" tabindex="-1">Install Fortify <a class="header-anchor" href="#install-fortify" aria-hidden="true">#</a></h2><p>The full documentation can be found on the <a href="https://laravel.com/docs/9.x/fortify" target="_blank" rel="noopener noreferrer">Laravel website</a>.</p><div class="language-php"><pre><code>composer <span class="token keyword">require</span> laravel<span class="token operator">/</span>fortify
php artisan vendor<span class="token punctuation">:</span>publish <span class="token operator">--</span>provider<span class="token operator">=</span><span class="token string double-quoted-string">&quot;Laravel\\Fortify\\FortifyServiceProvider&quot;</span>
php artisan migrate
</code></pre></div><p>Ensure the FortifyServiceProvider class is registered within the providers array of your application&#39;s config/app.php file.</p><div class="language-php"><pre><code><span class="token comment">/*
 * Application Service Providers...
 */</span>

<span class="token class-name class-name-fully-qualified static-context">App<span class="token punctuation">\\</span>Providers<span class="token punctuation">\\</span>FortifyServiceProvider</span><span class="token operator">::</span><span class="token keyword">class</span><span class="token punctuation">,</span>
</code></pre></div><h2 id="database-seeding" tabindex="-1">Database Seeding <a class="header-anchor" href="#database-seeding" aria-hidden="true">#</a></h2><p>Set up a seed for adding a test user, in the DatabaseSeeder.php file add the following:</p><div class="language-php"><pre><code><span class="token class-name class-name-fully-qualified static-context"><span class="token punctuation">\\</span>App<span class="token punctuation">\\</span>Models<span class="token punctuation">\\</span>User</span><span class="token operator">::</span><span class="token function">factory</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">)</span><span class="token operator">-&gt;</span><span class="token function">create</span><span class="token punctuation">(</span>
    <span class="token punctuation">[</span>
        <span class="token string single-quoted-string">&#39;name&#39;</span> <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;Luke Skywalker&#39;</span><span class="token punctuation">,</span>
        <span class="token string single-quoted-string">&#39;email&#39;</span> <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;luke@jedi.com&#39;</span><span class="token punctuation">,</span>
        <span class="token string single-quoted-string">&#39;email_verified_at&#39;</span> <span class="token operator">=&gt;</span> <span class="token constant">null</span><span class="token punctuation">,</span>
    <span class="token punctuation">]</span>
<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre></div><p>Run the migrations:</p><div class="language-php"><pre><code>php artisan migrate <span class="token operator">--</span>seed
</code></pre></div>`,27),o=[p];function l(c,i,r,u,d,k){return s(),n("div",null,o)}var f=a(t,[["render",l]]);export{g as __pageData,f as default};
